final:
module top_module(
    input X_a,
    input b,
    output r
);
    assign r = ~(X_a & b);
endmodule

module D(
    input X_a,
    input b,
    output r
);
    assign r = ~(X_a & b);
endmodule

module top_module(
    input X_a,
    input b,
    output r
);
    wire c1_out, c2_out, d1_out, d2_out;
    wire or_out, nor_out;

    C c1(.X_a(X_a), .b(b), .r(c1_out));
    C c2(.X_a(X_a), .b(b), .r(c2_out));
    D d1(.X_a(X_a), .b(b), .r(d1_out));
    D d2(.X_a(X_a), .b(b), .r(d2_out));

    assign or_out = c1_out | d1_out;
    assign nor_out = ~(c2_out | d2_out);

    assign r = or_out ^ nor_out;
endmodule
